-- 1. Rochester × Web Design
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'web-design',
  'rochester',
  'Rochester is a city whose character is defined by layers of history, from the Norman castle and England''s second oldest cathedral to the Dickensian streetscapes that draw visitors year-round, and your website must communicate that depth without feeling like a museum exhibit. The High Street''s independent shops, the creative quarter''s antique dealers and galleries, and the growing food and drink scene all serve a diverse audience: heritage tourists exploring the castle and cathedral, Dickens Festival visitors, Chatham Dockyard day-trippers extending their visit, and the Medway Towns resident population who form your year-round customer base. A website that speaks only to tourists misses the locals who sustain you through winter. One that speaks only to locals misses the heritage visitors who discover you on a castle visit. We build Rochester websites that balance these audiences, creating fast, modern, mobile-first sites that honour the city''s historic character while driving the enquiries, bookings, and sales that keep independent Rochester businesses thriving.',
  'Rochester''s commercial activity concentrates along the High Street, one of the finest preserved historic high streets in England, running from the castle at the southern end past the cathedral and Guildhall Museum toward the Corn Exchange. The independent shops, antique dealers, and eateries lining this stretch serve both the tourist trade and local residents. Rochester Cathedral, the second oldest in England, and Rochester Castle anchor the heritage tourism economy. The Dickens connection runs deep, with several novels set in and around the city and the annual Dickens Festival drawing thousands. Chatham Dockyard sits nearby, creating an extended heritage visitor catchment. Rochester forms part of the Medway Towns, with a local population of approximately 30,000 and the wider Medway area providing a substantial residential catchment.',
  'Rochester''s web design market is divided between the heritage tourism sector, where businesses sometimes benefit from VisitKent or Medway Council digital resources, and the independent business community, where website quality varies enormously. Several High Street businesses have invested in quality sites, but many others operate on templates or outdated builds that fail to capture the city''s character or convert visitors effectively. The proximity to London means some businesses use London agencies, paying premium rates for sites that lack genuine Rochester local knowledge.',
  'We approach Rochester web projects by understanding the dual audience every city-centre business serves. For heritage-adjacent businesses near the castle and cathedral, we build sites with structured data that captures tourism searches while creating compelling direct-visit experiences. For High Street independents, we create sites that reflect the artisan and antique character of Rochester''s shopping scene. For wider Medway service businesses, we build conversion-focused sites with strong local SEO targeting the entire Medway Towns area.',
  '{"population": 30000, "wider_area": "Medway Towns", "key_areas": ["High Street", "Castle area", "Cathedral precinct", "Corn Exchange", "Creative quarter"], "notable_landmarks": ["Rochester Castle", "Rochester Cathedral", "Guildhall Museum", "Corn Exchange"]}',
  '[{"title": "Rochester tourism businesses losing direct visitors to third-party platforms", "description": "A business near Rochester Castle or the Cathedral invests in a physical presence that attracts tourists, but those tourists book through TripAdvisor, Google Maps, or Visit Kent rather than directly. Without a website that ranks independently and converts visitors, Rochester heritage businesses pay commissions or lose attribution entirely."}, {"title": "Historic High Street businesses with websites that undermine their physical charm", "description": "Rochester''s High Street is one of the most attractive in Kent, yet many of its independent shops and eateries have websites that look nothing like the curated, characterful businesses they represent. A beautiful antique shop with a template website creates a jarring disconnect that loses online browsers before they ever visit in person."}, {"title": "No mobile experience for visitors exploring Rochester on foot", "description": "Tourists walking from Rochester Castle along the High Street to the Cathedral search on their phones for somewhere to eat, a gift shop, or an antique dealer. Rochester business websites that are not mobile-optimised lose these walk-in discovery moments to competitors who look better on a phone screen."}]',
  '[{"title": "Heritage-aware Rochester web design that drives modern results", "description": "We create websites that honour Rochester''s historic character while delivering contemporary commercial performance. For businesses near the castle and cathedral, this means design that feels premium and appropriate to the heritage setting, paired with booking tools, clear calls to action, and mobile-first performance."}, {"title": "Mobile-first builds for Rochester''s on-foot visitor economy", "description": "Every Rochester site we build loads in under two seconds on mobile with thumb-friendly navigation. Visitors exploring the High Street, castle grounds, or cathedral precinct can discover your business, check your offerings, and take action before they walk past your door."}, {"title": "Medway-wide SEO foundations in every Rochester website", "description": "We structure every Rochester site for visibility across the Medway Towns and wider Kent heritage tourism searches. Location-specific schema markup, content targeting Rochester, Chatham, and Strood, and structured data that feeds into Google''s tourism and local business results."}]',
  '[{"question": "Can you build a Rochester website that serves both tourists and locals?", "answer": "Yes, this dual-audience approach is central to our Rochester web design strategy. We create distinct user pathways so heritage tourists and Medway residents both find relevant content quickly. Tourism visitors see seasonal information and booking tools. Local customers see service details and clear contact options."}, {"question": "How much does a Rochester business website cost?", "answer": "Rochester projects range from focused sites for High Street independents through to complex heritage tourism builds with booking integration. We provide fixed quotes after understanding your specific needs. Every project includes mobile optimisation, on-page SEO, and content written for the Rochester and Medway market."}, {"question": "Will my Rochester website rank for heritage tourism searches?", "answer": "We build structured data and content strategies specifically designed to compete in Rochester''s heritage tourism search landscape. While Rochester Castle and Cathedral sites carry enormous authority, we target the commercial searches that these institutional sites cannot serve, such as dining, shopping, and accommodation near Rochester Castle."}, {"question": "How long does a Rochester web design project take?", "answer": "Most Rochester projects launch within four to six weeks. Heritage tourism businesses with booking requirements may need six to eight weeks. We schedule around the Dickens Festival and peak tourism periods to ensure your site is live before the busiest seasons."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
