-- 6. Rochester × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'rochester',
  'Rochester is one of the most photographed towns in Kent. The castle against a sunset sky, the cathedral interior, the Dickens Festival in full costume, the High Street''s timber-framed shop fronts: this content circulates widely on social media, creating organic awareness that most towns would envy. Yet the majority of Rochester businesses fail to capture any value from this visual economy. Their social profiles are afterthoughts: blurry logo images, outdated information, inconsistent branding, and no strategy for engaging the audience that discovers Rochester through these shared images. When a potential customer sees a stunning photograph of the High Street and clicks through to find a local business, they encounter a Facebook page with incorrect opening hours and an Instagram profile with three posts from last year. Rochester''s visual appeal is doing the marketing work for free; your social profiles just need to be ready to receive the traffic.',
  'Rochester''s social media landscape benefits from the city''s photogenic qualities. Instagram content featuring the castle, cathedral, and High Street generates strong organic engagement. Facebook remains important for the Medway residential community and local event promotion. The Dickens Festival creates annual social media spikes with costumed attendees sharing thousands of posts. Heritage tourism accounts regularly feature Rochester, creating discovery opportunities for local businesses. The creative quarter and antique shops generate interest from specialist collector communities on social media.',
  'Social media quality among Rochester businesses is inconsistent. A few High Street venues maintain strong Instagram accounts that leverage the heritage setting effectively. Some antique dealers have built specialist followings. But the majority of Rochester businesses have underdeveloped profiles that miss the organic discovery traffic the city''s visual appeal generates. Google Business Profile adoption is particularly poor, with many businesses unclaimed or displaying inaccurate information.',
  'We set up Rochester social media profiles to capitalise on the city''s extraordinary visual appeal. Every profile receives professional imagery that leverages the castle, cathedral, and High Street setting, optimised descriptions targeting Rochester and Medway searches, and a content framework aligned with the heritage tourism calendar including the Dickens Festival and seasonal events.',
  '{"population": 30000, "wider_area": "Medway Towns (270,000+)", "key_areas": ["High Street", "Castle area", "Cathedral precinct", "Creative quarter", "Corn Exchange"], "social_landscape": "highly photogenic, strong organic content generation around castle, cathedral, and Dickens Festival"}',
  '[{"title": "Rochester''s photogenic heritage generating social media traffic that businesses cannot capture", "description": "Thousands of Instagram posts featuring Rochester Castle and the High Street circulate weekly. Potential customers discover Rochester through these images and search for local businesses to visit. Those businesses with poor or absent social profiles are invisible at the exact moment interest peaks."}, {"title": "Dickens Festival social media surge with no commercial capture", "description": "The Dickens Festival generates enormous social media activity with costumed attendees sharing photos across platforms. Rochester businesses could ride this wave of attention, but most have profiles too poorly set up to benefit. The festival''s social media impact passes without creating any lasting commercial connection."}, {"title": "Unclaimed Google Business Profiles costing Rochester businesses walk-in trade", "description": "Heritage visitors searching for businesses near Rochester Castle on Google find a map peppered with unclaimed or poorly maintained listings. Without photos, reviews, and accurate hours, these listings do more harm than good, suggesting businesses that are inactive or unreliable."}]',
  '[{"title": "Heritage-leveraging social media setup for Rochester businesses", "description": "We set up your Instagram, Facebook, and Google Business profiles with professional imagery that uses Rochester''s castle, cathedral, and High Street setting as a brand asset. Your profiles are designed to capture the organic discovery traffic that the city''s visual appeal generates, converting heritage tourism interest into business engagement."}, {"title": "Dickens Festival and event-ready social profiles", "description": "We prepare your social profiles with content strategies and templates designed for Rochester''s event calendar. When the Dickens Festival, heritage weekends, or seasonal events drive social media surges, your business is positioned to capture attention with prepared, branded content that converts interest into visits and bookings."}, {"title": "Google Business Profile optimisation for Rochester walk-in discovery", "description": "We claim, verify, and fully optimise your Google Business Profile with professional imagery, comprehensive business information, and structured review generation. For High Street businesses in the castle-to-cathedral corridor, an optimised listing is the difference between capturing walk-in visitors and being invisible to them."}]',
  '[{"question": "Which social media platforms matter most for a Rochester business?", "answer": "Instagram is essential for leveraging Rochester''s visual heritage appeal. Facebook reaches the Medway residential community and local event audience. Google Business Profile is critical for walk-in discovery around the castle and High Street. We assess your business type to prioritise platforms correctly."}, {"question": "Can social media help my Rochester business benefit from the Dickens Festival?", "answer": "Yes. We create Festival-specific content strategies and templates so your business is ready when the social media surge hits. Hashtagged, location-tagged, and visually compelling content during the Festival connects your business to the thousands of posts and searches the event generates."}, {"question": "How long does social media setup take for a Rochester business?", "answer": "Complete setup covering Instagram, Facebook, and Google Business Profile takes five to seven working days. This includes professional imagery leveraging the Rochester heritage context, optimised profiles, branded templates, and a content framework. High Street businesses may benefit from additional photography capturing the streetscape setting."}, {"question": "Do you manage Rochester social media ongoing or just set it up?", "answer": "Our core service is professional setup with a content framework that makes ongoing management achievable. We also offer full management for businesses that prefer to hand off posting entirely. Many Rochester clients find the heritage calendar provides natural content hooks that make self-management straightforward with our templates."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
